// All skills flattened in one array with proper icons
const ALL_TECH_LOGOS = [
  { name: 'React' },
  { name: 'Redux' },
  { name: 'JavaScript' },
  { name: 'HTML/CSS' },
  { name: 'Tailwind CSS' },
  { name: 'Node.js' },
  { name: 'Express.js' },
  { name: 'REST API' },
  { name: 'Prisma' },
  { name: 'PostgreSQL' },
  { name: 'MongoDB' },
  { name: 'Firebase' },
  { name: 'Supabase' },
  { name: 'Redis' },
  { name: 'Git' },
  { name: 'Vite' },
  { name: 'VS Code' },
  { name: 'Postman' },
  { name: 'Docker' },
  { name: 'DigitalOcean' },
  { name: 'ChromaDB' },
  { name: 'Qdrant' },
]

function TechLogoItem({ name }) {
  const icon = icons[name]
  return (
    <div className="flex flex-col items-center gap-2.5 px-3 select-none group/item">
      <div
        className="
          w-14 h-14 rounded-2xl flex items-center justify-center
          bg-[var(--color-bg-secondary)] border border-[var(--color-border)]/60
          group-hover/item:border-[var(--color-accent)]/30
          group-hover/item:bg-[var(--color-bg-tertiary)]
          transition-all duration-300
          shadow-sm
        "
      >
        <div className="w-7 h-7">{icon}</div>
      </div>
      <span className="text-xs font-medium text-[var(--color-text-muted)] group-hover/item:text-[var(--color-text-secondary)] transition-colors whitespace-nowrap">
        {name}
      </span>
    </div>
  )
}

export default function SkillsSection() {
  const { t } = useTranslation()

  const logos = useMemo(
    () =>
      ALL_TECH_LOGOS.map(tech => ({
        node: <TechLogoItem name={tech.name} />,
        title: tech.name,
      })),
    []
  )

  return (
    <SectionWrapper
      id="skills"
      title={t('skills.title')}
      subtitle={t('skills.subtitle')}
    >
      <div className="space-y-8">
        {/* Single marquee strip */}
        <LogoLoop
          logos={logos}
          speed={60}
          direction="left"
          logoHeight={90}
          gap={8}
          pauseOnHover
          fadeOut
          fadeOutColor="#0f172a"
          scaleOnHover
          ariaLabel="Tech stack"
        />
      </div>
    </SectionWrapper>
  )
}
